/**
 * Vercel Speed Insights Integration
 * Official implementation for static HTML sites
 * Tracks Core Web Vitals and page performance metrics
 */

(function() {
  // Initialize the Speed Insights queue
  window.si = window.si || function () { 
    (window.siq = window.siq || []).push(arguments); 
  };

  // Create and append the Speed Insights script
  // The unique path is automatically generated by Vercel when Speed Insights is enabled
  const script = document.createElement('script');
  script.defer = true;
  script.src = '/_vercel/speed-insights/script.js';
  
  // Error handling for script loading
  script.onerror = function() {
    console.warn('Vercel Speed Insights: Script failed to load. Ensure Speed Insights is enabled in your Vercel project settings.');
  };
  
  document.head.appendChild(script);
})();
